pg_get_functiondef:
CREATE OR REPLACE FUNCTION public.trial_eligibility()
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$

declare

eligible boolean;

begin

select not exists(

select 1

from public.trial_access

where

user_id=auth.uid()

)

into eligible;

return coalesce(

eligible,

false

);

end;

$function$

CREATE OR REPLACE FUNCTION public.trigger_admin_event()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$

begin

insert into

public.admin_events(

event_type,

created_at

)

values(

tg_table_name,

now()

);

return new;

end;

$function$
